import { useState } from "react";
import { Category } from "../../../model/categoryModel";
import { fetchSubcategories } from "../../../service/categoryService";
import {useTranslation} from "react-i18next";

export const useHeaderModel = () => {
    const { t } = useTranslation<'translation'>();

    const categories: Category[] = [
        { id: 1, name: t('type_1'), svg: '/assets/type_1.svg', url: 'Հեռուստացույց', parent_id: null },
        { id: 2, name: t('type_2'), svg: '/assets/type_2.svg', url: 'Օդորակիչներ', parent_id: null },
        { id: 3, name: t('type_3'), svg: '/assets/type_3.svg', url: 'products/', parent_id: null },
        { id: 4, name: t('type_4'), svg: '/assets/type_4.svg', url: 'products/', parent_id: null },
        { id: 5, name: t('type_5'), svg: '/assets/type_5.svg', url: 'products/', parent_id: null },
        { id: 6, name: t('type_6'), svg: '/assets/type_6.svg', url: 'products/', parent_id: null },
        { id: 7, name: t('type_7'), svg: '/assets/type_7.svg', url: 'products/', parent_id: null },
        { id: 8, name: t('type_8'), svg: '/assets/type_8.svg', url: 'products/', parent_id: null },
        { id: 9, name: t('type_9'), svg: '/assets/type_9.svg', url: 'products/', parent_id: null },
        { id: 10, name: t('type_10'), svg: '/assets/type_10.svg', url: 'products/', parent_id: null },
        { id: 11, name: t('type_11'), svg: '/assets/type_11.svg', url: 'products/', parent_id: null },
        { id: 12, name: t('type_12'), svg: '/assets/type_12.svg', url: 'products/', parent_id: null },
    ];

    const [hoveredCategoryId, setHoveredCategoryId] = useState<number | null>(null);
    const [subcategories, setSubcategories] = useState<Category[]>([]);
    const [activeCategory, setActiveCategory] = useState<number | null>(null);

    const handleCategoryHover = async (categoryId: number) => {
        setHoveredCategoryId(categoryId);
        const fetchedSubcategories = await fetchSubcategories(categoryId);
        setSubcategories(fetchedSubcategories);
        setActiveCategory(categoryId);
    };

    const handleCategoryLeave = () => {
        setActiveCategory(null);
    };

    return { categories, subcategories, hoveredCategoryId, handleCategoryHover, handleCategoryLeave };
};
